import '../App.css';
import '../../node_modules/bootstrap/dist/css/bootstrap.css'
import React, { useState, useEffect, useCallback } from 'react';
import { Link, NavLink, useNavigate } from 'react-router-dom';
import axios from 'axios';
import BootstrapTable from 'react-bootstrap-table-next';

// const columns = [{
//   dataField: 'id',
//   text: 'ID'
// }, {
//   dataField: 'name_sing',
//   text: 'Название дорожного знака'
// }];

const api = axios.create({ 
    baseURL: 'http://localhost:5000',
    withCredentials: true 
});


function Sing() {
  const [tableData, setTableData] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [debugInfo, setDebugInfo] = useState({});
  const navigate = useNavigate();

  // Функция для преобразования данных в формат для BootstrapTable
  const transformDataForTable = (data) => {
    if (!Array.isArray(data) || data.length === 0) {
      return [];
    }

    return data.map((item, index) => ({
      id: index + 1, // Добавляем уникальный id для keyField
      ...item
    }));
  };

  // Функция для создания колонок на основе данных
  const createColumns = (data) => {
    if (!Array.isArray(data) || data.length === 0) {
      return [];
    }

    const sampleItem = data[0];
    return Object.keys(sampleItem).map(key => ({
      dataField: key,
      text: key.charAt(0).toUpperCase() + key.slice(1), // Заглавная первая буква
      sort: true,
      formatter: (cell, row) => {
        if (cell === null || cell === undefined) {
          return '—';
        }
        if (typeof cell === 'object') {
          return JSON.stringify(cell);
        }
        return String(cell);
      }
    }));
  };

  const fetchTableData = useCallback(async () => {
    setLoading(true);
    setError('');

    try {
      const response = await api.get('/table');

      setDebugInfo({
        status: response.status,
        timestamp: new Date().toISOString(),
        dataLength: response.data?.length || 0
      });

      if (response.status === 200) {
        setTableData(Array.isArray(response.data) ? response.data : [response.data]);
      }
    } catch (err) {
      let errorMessage = '';

      if (err.response) {
        errorMessage = err.response.data.message || `Ошибка ${err.response.status}`;
        setDebugInfo(prev => ({
          ...prev,
          errorResponse: err.response.data,
          errorStatus: err.response.status
        }));

        if (err.response.status === 401) {
          setTimeout(() => navigate('/login'), 1500);
        }
      } else if (err.request) {
        errorMessage = 'Нет ответа от сервера';
      } else {
        errorMessage = 'Ошибка при отправке запроса';
      }

      setError(errorMessage);
    } finally {
      setLoading(false);
    }
  }, [navigate]);

  const handleLogout = () => {
    // Очистка cookies
    document.cookie.split(';').forEach(cookie => {
      const [key] = cookie.trim().split('=');
      if (key) {
        document.cookie = `${key}=; expires=Thu, 01 Jan 1970 00:00:00 UTC; path=/;`;
      }
    });
    navigate('/login');
  };

  const handleBackToLogin = () => {
    navigate('/login');
  };

  useEffect(() => {
    fetchTableData();
  }, [fetchTableData]);

  // Подготавливаем данные и колонки для BootstrapTable
  const transformedData = transformDataForTable(tableData);
  const columns = createColumns(tableData);

  return (
    <div className="app-container">
      <div className="app-card">

        <div className="controls">
          {/* <button
            onClick={fetchTableData}
            disabled={loading}
            className="refresh-button"
          >
            {loading ? 'Загрузка...' : 'Обновить данные'}
          </button>

          <button
            onClick={() => {
              setTableData([]);
              setDebugInfo({});
            }}
            className="clear-button"
          >
            Очистить
          </button> */}
        </div>

        <div className="data-section">
          <h3 className="section-title">
            Таблица данных {tableData.length > 0 && `(${tableData.length} записей)`}
          </h3>

          {loading ? (
            <div className="loading-container">
              <div className="spinner"></div>
              <p>Загрузка данных...</p>
            </div>
          ) : transformedData.length > 0 ? (
            <div className="bootstrap-table-container">
              <BootstrapTable
                keyField="id"
                data={transformedData}
                columns={columns}
                bootstrap4
                striped
                hover
                condensed
                wrapperClasses="table-responsive"
                noDataIndication={() => (
                  <div className="no-data-message">
                    Нет данных для отображения
                  </div>
                )}
                headerClasses="table-header"
                rowClasses="table-row"
              />
            </div>
          ) : (
            <p className="no-data">Нет данных для отображения</p>
          )}
        </div>

        <div className="debug-section">
          <h4 className="debug-title">Информация о запросе:</h4>
          <pre className="debug-info">
            {JSON.stringify(debugInfo, null, 2)}
          </pre>
        </div>

        <div className="status-info">
          <div className="status-item">
            <span className="status-label">Статус авторизации:</span>
            <span className={`status-value ${error.includes('401') ? 'error' : 'success'}`}>
              {error.includes('401') ? '❌ Не авторизован' : '✅ Авторизован'}
            </span>
          </div>
          <div className="status-item">
            <span className="status-label">Данные:</span>
            <span className={`status-value ${tableData.length > 0 ? 'success' : 'empty'}`}>
              {tableData.length > 0 ? 'Загружены' : 'Нет данных'}
            </span>
          </div>
          <div className="status-item">
            <span className="status-label">Cookies:</span>
            <span className="status-value">
              {document.cookie ? 'Присутствуют' : 'Отсутствуют'}
            </span>
          </div>
        </div>
      </div>
    </div>
  );
}

export default Sing;
